// --- Firebase Initialization ---
const isLocalOnlyMode = typeof window !== 'undefined' && localStorage.getItem("force_local_mode") === "true";

let app: any;
let auth: any;
let db: any;

try {
  if (!isLocalOnlyMode) {
    app = initializeApp(firebaseConfig);
    auth = getAuth(app);
    db = firebaseConfig.firestoreDatabaseId ? getFirestore(app, firebaseConfig.firestoreDatabaseId) : getFirestore(app);
    console.log("[FIREBASE] Cloud Sync Mode active.");
  } else {
    console.log("[FIREBASE] EMERGENCY LOCAL MODE active. Firestore and Auth disabled.");
    // Provide dummy objects to prevent crashes
    auth = { onAuthStateChanged: () => () => {}, currentUser: null, signOut: () => Promise.resolve() };
    db = {}; 
  }
} catch (e) {
  console.error("Firebase initialization failed:", e);
}

export { auth, db, isLocalOnlyMode };

// --- Error Boundary ---
interface Props {
  children?: ReactNode;
}

interface State {
  hasError: boolean;
  error: Error | null;
}

class ErrorBoundary extends Component<Props, State> {
  constructor(props: Props) {
    super(props);
    this.state = { hasError: false, error: null };
  }

  public static getDerivedStateFromError(error: Error): State {
    return { hasError: true, error };
  }

  public componentDidCatch(error: Error, errorInfo: ErrorInfo) {
    console.error("Uncaught error:", error, errorInfo);
  }

  public render() {
    if (this.state.hasError) {
      return (
        <div className="min-h-screen bg-rose-50 flex items-center justify-center p-6 text-center">
          <div className="max-w-md w-full bg-white p-8 rounded-[2.5rem] shadow-2xl border border-rose-100">
            <div className="w-20 h-20 bg-rose-100 rounded-3xl flex items-center justify-center mx-auto mb-6 rotate-3">
              <AlertTriangle className="w-10 h-10 text-rose-600" />
            </div>
            <h1 className="text-2xl font-black text-rose-900 uppercase mb-4 tracking-tight">App Crash Detected</h1>
            <p className="text-rose-600 text-sm font-bold mb-6 leading-relaxed">
              Kuch technical issue ki wajah se App load nahi ho payi. 
              Niche diye gaye button se App ko Reset karein.
            </p>
            <div className="bg-rose-50 p-4 rounded-2xl mb-8 text-left">
              <p className="text-[10px] font-mono text-rose-700 break-all">
                {this.state.error?.toString()}
              </p>
            </div>
            <button
              onClick={() => {
                localStorage.clear();
                window.location.reload();
              }}
              className="w-full py-4 bg-rose-600 text-white rounded-2xl font-black uppercase tracking-widest shadow-lg shadow-rose-200 active:scale-95 transition-all"
            >
              Force Reset App
            </button>
          </div>
        </div>
      );
    }

    return this.props.children;
  }
}

// Error Handling Utility
interface FirestoreErrorInfo {
  error: string;
  operationType: "create" | "update" | "delete" | "list" | "get" | "write";
  path: string | null;
  authInfo: {
    userId: string;
    email: string;
    emailVerified: boolean;
    isAnonymous: boolean;
    providerInfo: { providerId: string; displayName: string; email: string }[];
  };
}

const handleFirestoreError = (
  error: any,
  operation: FirestoreErrorInfo["operationType"],
  path: string | null = null,
) => {
  const errorMsg = error?.message || String(error);

  // Benign errors in development environment (e.g. Vite HMR or Firebase networking)
  if (
    errorMsg.includes("failed to connect to websocket") ||
    errorMsg.includes("socket closed") ||
    errorMsg.includes("The client is offline")
  ) {
    console.warn("Benign Connection Warning (safe to ignore):", errorMsg);
    return;
  }

  if (errorMsg.includes("insufficient permissions")) {
    const errorInfo: FirestoreErrorInfo = {
      error: error.message,
      operationType: operation,
      path: path,
      authInfo: {
        userId: auth.currentUser?.uid || "anonymous",
        email: auth.currentUser?.email || "",
        emailVerified: (auth.currentUser as any)?.emailVerified || false,
        isAnonymous: auth.currentUser?.isAnonymous || false,
        providerInfo:
          auth.currentUser?.providerData.map((p) => ({
            providerId: p.providerId,
            displayName: p.displayName || "",
            email: p.email || "",
          })) || [],
      },
    };
    throw new Error(JSON.stringify(errorInfo));
  }
  throw error;
};

// Check Connection
const testConnection = async (setStatus: (s: any) => void, setError: (e: any) => void, attempts = 2) => {
  if (isLocalOnlyMode || !db || Object.keys(db).length === 0) {
    setStatus("UNAVAILABLE");
    setError("Emergency Local Mode Active");
    return;
  }
  try {
    if (attempts === 2) setStatus("CHECKING");
    
    // Create a real promise timeout of 4 seconds (instead of relying on AbortController)
    const timeoutPromise = new Promise((_, reject) =>
      setTimeout(() => reject(new Error("Firestore check timed out after 4s")), 4000)
    );

    try {
      // Try a direct fetch to bypass local state
      await Promise.race([
        getDocFromServer(doc(db, "config", "status")),
        timeoutPromise
      ]);
      setStatus("CONNECTED");
      setError(null);
      console.log("Firestore connection verified.");
    } catch (e: any) {
      throw e;
    }
  } catch (error: any) {
    if (attempts > 1) {
      console.log(`Connection attempt failed, retrying... (${attempts - 1} left)`);
      setTimeout(() => testConnection(setStatus, setError, attempts - 1), 1500);
      return;
    }

    const msg = error?.message || String(error);
    setError(msg);
    if (
      error?.code === "unavailable" ||
      msg.toLowerCase().includes("unavailable") ||
      msg.toLowerCase().includes("could not reach") ||
      msg.toLowerCase().includes("timeout") ||
      msg.toLowerCase().includes("timed out")
    ) {
      setStatus("UNAVAILABLE");
      console.warn(
        "Firestore is currently unavailable. Possible network/firewall issue.",
      );
    } else if (msg.includes("the client is offline")) {
      setStatus("DISCONNECTED");
      console.error(
        "Client appears to be offline. Verify your internet connection.",
      );
    } else {
      // If it's a permission error or something else, but reached the server
      if (msg.includes("permission") || msg.includes("denied")) {
        setStatus("CONNECTED");
        console.log("Reached server but with restricted permissions (expected).");
      } else {
        setStatus("DISCONNECTED");
        console.error("Firestore initialization check failed:", error);
      }
    }
  }
};

