const WoodenAnalogClock = ({
  time,
  size = 160,
}: {
  time: Date;
  size?: number;
}) => {
  const seconds = time.getSeconds();
  const minutes = time.getMinutes();
  const hours = time.getHours();

  const secDeg = (seconds / 60) * 360;
  const minDeg = ((minutes + seconds / 60) / 60) * 360;
  const hourDeg = (((hours % 12) + minutes / 60) / 12) * 360;

  return (
    <div
      className="relative rounded-full border-4 border-[#8b5a2b] bg-[#d2b48c] shadow-2xl flex items-center justify-center overflow-hidden"
      style={{
        width: size,
        height: size,
        backgroundImage:
          "linear-gradient(135deg, #e6cc99 0%, #d2b48c 50%, #c1a376 100%)",
        boxShadow:
          "inset 0 0 30px rgba(0,0,0,0.2), 0 10px 25px rgba(0,0,0,0.3)",
      }}
    >
      {/* Vertical grain lines simulation */}
      <div
        className="absolute inset-0 opacity-20 pointer-events-none"
        style={{
          backgroundImage:
            "repeating-linear-gradient(90deg, transparent, transparent 8px, #5d3a1a 9px)",
        }}
      />

      {/* Center dot */}
      <div className="absolute w-2.5 h-2.5 bg-slate-900 rounded-full z-20 shadow-sm" />

      {/* Hour hand */}
      <div
        className="absolute bg-slate-900 rounded-full origin-bottom z-10"
        style={{
          width: size * 0.0375,
          height: size * 0.25,
          transform: `rotate(${hourDeg}deg)`,
          bottom: "50%",
          left: `calc(50% - ${size * 0.01875}px)`,
        }}
      />

      {/* Minute hand */}
      <div
        className="absolute bg-slate-700 rounded-full origin-bottom z-10"
        style={{
          width: size * 0.025,
          height: size * 0.35,
          transform: `rotate(${minDeg}deg)`,
          bottom: "50%",
          left: `calc(50% - ${size * 0.0125}px)`,
        }}
      />

      {/* Second hand */}
      <div
        className="absolute bg-red-600 origin-bottom z-10"
        style={{
          width: size * 0.0125,
          height: size * 0.4,
          transform: `rotate(${secDeg}deg)`,
          bottom: "50%",
          left: `calc(50% - ${size * 0.00625}px)`,
        }}
      />

      {/* Roman Numerals */}
      {ROMAN_NUMERALS.map((num, i) => (
        <div
          key={num}
          className="absolute text-slate-900 font-serif font-bold"
          style={{
            fontSize: Math.max(size * 0.08, 9),
            transform: `rotate(${i * 30}deg) translateY(-${size * 0.38}px) rotate(-${i * 30}deg)`,
            top: `calc(50% - ${Math.max(size * 0.04, 6)}px)`,
            left: `calc(50% - ${size * 0.075}px)`,
            width: `${size * 0.15}px`,
            textAlign: "center",
          }}
        >
          {num}
        </div>
      ))}
    </div>
  );
};

// --- Helper Functions ---

const createSafeFile = (
  bits: BlobPart[],
  name: string,
  options?: FilePropertyBag,
) => {
  try {
    return new File(bits, name, options);
  } catch (e) {
    console.warn("File constructor failed, falling back to Blob:", e);
    // Fallback for browsers where new File() is not a constructor (Illegal constructor)
    const blob = new Blob(bits, options);
    // Manually add the properties if possible (not many browsers allow this but it's a best effort)
    Object.defineProperty(blob, "name", { value: name, writable: false });
    Object.defineProperty(blob, "lastModified", {
      value: Date.now(),
      writable: false,
    });
    return blob as unknown as File;
  }
};

const safeJSONParse = (data: string | null, fallback: any) => {
  if (!data) return fallback;
  try {
    return JSON.parse(data);
  } catch (e) {
    console.error("JSON Parse Error:", e);
    return fallback;
  }
};

const safeLocalStorageSetItem = (key: string, value: string) => {
  try {
    localStorage.setItem(key, value);
  } catch (e: any) {
    console.error(`localStorage Error for key "${key}":`, e);
    if (
      e.name === "QuotaExceededError" ||
      e.name === "NS_ERROR_DOM_QUOTA_REACHED"
    ) {
      // Potentially alert the user that storage is full
      console.warn("Storage quota exceeded. Some data may not be saved.");
    }
  }
};

