  useEffect(() => {
    const checkYearlyReminders = () => {
      const today = new Date();
      today.setHours(0, 0, 0, 0);
      const thirtyDaysLater = new Date();
      thirtyDaysLater.setDate(today.getDate() + 30);
      thirtyDaysLater.setHours(23, 59, 59, 999);

      const reminders = yearlyTasks.filter((task) => {
        let taskDueDate: Date | null = null;

        if (task.dueDate) {
          taskDueDate = new Date(task.dueDate);
        } else if (task.type === "YEARLY" && task.dayOrDate) {
          // If dueDate is missing, try to infer from month in dayOrDate
          const monthIndex = MONTHS.indexOf(task.dayOrDate.toUpperCase());
          if (monthIndex !== -1) {
            // Assume last day of that month in the current year
            const currentYear = today.getFullYear();
            taskDueDate = new Date(currentYear, monthIndex + 1, 0); // last day of month
            
            // If that date has already passed for this year, check next year
            if (taskDueDate < today) {
              taskDueDate = new Date(currentYear + 1, monthIndex + 1, 0);
            }
          }
        }

        if (!taskDueDate || isNaN(taskDueDate.getTime())) return false;
        
        // Match the user's request: Reminder 1 month in advance
        // So if dueDate is within the next 30 days
        return taskDueDate >= today && taskDueDate <= thirtyDaysLater;
      });

      setUpcomingYearlyReminders(reminders);
    };

    checkYearlyReminders();
    const interval = setInterval(checkYearlyReminders, 3600000);
    return () => clearInterval(interval);
  }, [yearlyTasks]);

