  const handleShareToWhatsApp = (isBusiness = false) => {
    if (!globalShareConfig) return;
    const text = `*${globalShareConfig.title}*\n${globalShareConfig.text}`;
    const baseUrl = isBusiness ? "https://wa.me/?text=" : "https://wa.me/?text=";
    // Note: WhatsApp Desktop/Mobile doesn't have a distinct "wa.me" subdomain for business
    // usually users have either one or both. The best way is to use the standard share link.
    // However, some users might want a specific check. For now, we use the standard link.
    window.open(`${baseUrl}${encodeURIComponent(text)}`, "_blank");
  };

  const handleShareToGmail = () => {
    if (!globalShareConfig) return;
    const subject = encodeURIComponent(globalShareConfig.title);
    const body = encodeURIComponent(`${globalShareConfig.text}\n\nSent via ARYAASSOCIATES Portal`);
    window.open(`mailto:?subject=${subject}&body=${body}`, "_blank");
  };

  const handleNativeShare = async () => {
    if (!globalShareConfig) return;
    
    // If navigator.share is not available at all
    if (!navigator.share) {
      setNotification({
        message: "📂 Native sharing not supported. Use WhatsApp or Download instead.",
        type: "info"
      });
      return;
    }

    try {
      const shareData: any = {
        title: globalShareConfig.title,
        text: globalShareConfig.text,
      };
      
      if (globalShareConfig.file) {
        const file = createSafeFile(
          [globalShareConfig.file.blob], 
          globalShareConfig.file.name, 
          { type: globalShareConfig.file.type }
        );
        if (navigator.canShare && navigator.canShare({ files: [file] })) {
          shareData.files = [file];
        }
      }
      
      await navigator.share(shareData);
      setGlobalShareConfig(null);
    } catch (error: any) {
      console.error("Native share failed:", error);
      // Fallback: If it's not a user-cancellation, offer download
      if (error.name !== "AbortError") {
        if (globalShareConfig.file) {
          const url = URL.createObjectURL(globalShareConfig.file.blob);
          const link = document.createElement("a");
          link.href = url;
          link.download = globalShareConfig.file.name;
          document.body.appendChild(link);
          link.click();
          document.body.removeChild(link);
          URL.revokeObjectURL(url);
          setNotification({
            message: "📂 Sharing blocked by system. File downloaded instead.",
            type: "info",
          });
        }
      }
      setGlobalShareConfig(null);
    }
  };

  const handleSyncBusinessSheet = async (overrideSheetId?: any) => {
    const finalSheetId = (typeof overrideSheetId === "string" && overrideSheetId) 
      ? overrideSheetId 
      : businessSheetId;

    if (!finalSheetId) {
      setNotification({ message: "Please enter a Spreadsheet ID first.", type: "error" });
      return;
    }
    
    setIsSyncingBusinessSheet(true);
    setNotification({ message: "⏳ Syncing Business Masters from Google Sheet...", type: "info" });
    
    try {
      // Save settings to cloud immediately before syncing
      if (currentUser && userRole === "ADMIN") {
        try {
          await setDoc(doc(db, "appConfig", "system"), { 
            businessSheetId: finalSheetId,
            businessSheetRange
          }, { merge: true });
        } catch (dbErr) {
          console.warn("Could not save config to Firestore (Offline mode?):", dbErr);
          // Don't block sync if only settings save failed
        }
      }

      const response = await fetch("/api/google/sheets/sync-businesses", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        credentials: "include",
        body: JSON.stringify({
          spreadsheetId: finalSheetId,
          range: businessSheetRange,
          uid: auth.currentUser?.uid
        })
      });
      
      const contentType = response.headers.get("content-type");
      if (!contentType || !contentType.includes("application/json")) {
        const text = await response.text();
        console.error("Non-JSON response from server:", text.substring(0, 500));
        throw new Error("Server returned an invalid response (HTML). The server might be restarting or there is a configuration error. Please try again in 5-10 seconds.");
      }

      const result = await response.json();
      if (!response.ok) throw new Error(result.error || "Sync failed");
      
      let message = `✅ Sync Complete!\n`;
      message += `• Business Master (Sheet 1) -> Added: ${result.added || 0}, Updated: ${result.updated || 0}\n`;
      if (result.usedTeamSheet) {
        message += `• Team Member Master (Sheet 2) -> Added: ${result.teamAdded || 0}, Updated: ${result.teamUpdated || 0}`;
      }
      
      if (result.errors && result.errors.length > 0) {
        message += `\nNote: ${result.errors.length} rows failed. Example: ${result.errors[0]}`;
        setNotification({ message, type: "warning" });
      } else {
        setNotification({ message, type: "success" });
      }
      
      // Save settings
      setBusinessSheetId(finalSheetId);
      safeLocalStorageSetItem("arya_business_sheet_id", finalSheetId);
      safeLocalStorageSetItem("arya_business_sheet_range", businessSheetRange);
      
    } catch (error: any) {
      console.error("Business Sheet Sync Error:", error);
      
      const isCloudBlocked = error.message && (error.message.includes("Error 7") || error.message.includes("PERMISSION_DENIED") || error.message.includes("IAM"));
      
      if (isCloudBlocked) {
        const proceedLocal = await showConfirmPromise(
          "Cloud Error (Error 7)",
          "❌ Cloud connection is blocked by permissions.\n\nWould you like to import data directly to your Browser (Local Storage)? This will bypass the Cloud error.",
          "warning"
        );
        if (proceedLocal) {
          try {
            setNotification({ message: "⏳ Importing data locally...", type: "info" });
            const localRes = await fetch(`/api/google/sheets/fetch-businesses?spreadsheetId=${finalSheetId}&range=${businessSheetRange}&uid=${currentUser?.uid}`);
            const localData = await localRes.json();
            
            if (localData.success && localData.businesses) {
              setBusinesses(prev => {
                const combined = [...prev];
                localData.businesses.forEach((newBiz: any) => {
                   const exists = combined.some(b => b.businessCode === newBiz.businessCode);
                   if (!exists) combined.push(newBiz);
                });
                return combined;
              });
              setNotification({ message: `✅ Success! Imported ${localData.count} businesses locally.`, type: "success" });
              setIsCloudTroubleshootOpen(true); // Still show troubleshooting but data is there
              return;
            } else {
              throw new Error(localData.error || "Local fetch failed");
            }
          } catch (localErr: any) {
             setNotification({ message: "❌ Local Import also failed: " + localErr.message, type: "error" });
          }
        } else {
           setNotification({ message: "❌ Cloud Error: " + error.message, type: "error" });
        }
      } else {
        setNotification({ message: "❌ Sync Error: " + error.message, type: "error" });
      }

      if (error.message && error.message.includes("Auth required")) {
         handleGoogleApiConnect();
      }
    } finally {
      setIsSyncingBusinessSheet(false);
    }
  };

