  const handlePickContact = async (fieldKey?: string) => {
    if (!("contacts" in navigator && "select" in (navigator as any).contacts)) {
      setNotification({
        message: "👤 Contact Picker not supported on this browser/device.",
        type: "error"
      });
      return;
    }

    try {
      const props = ["name", "tel"];
      const opts = { multiple: false };
      const contacts = await (navigator as any).contacts.select(props, opts);

      if (contacts.length > 0) {
        const picked = contacts[0];
        const name = picked.name?.[0] || "";
        const phone = picked.tel?.[0] || "";

        if (masterType === "BUSINESS") {
          // If a specific field was requested (like mobile)
          if (fieldKey) {
            setMasterFormData(prev => ({
              ...prev,
              [fieldKey]: phone
            }));
          } else {
            // Default behavior: Fill Name and logic for auto-detecting phone field
            setMasterFormData(prev => {
              const newData = { ...prev };
              if (!newData.name) newData.name = name;
              if (!newData.contactPerson) newData.contactPerson = name;
              
              const phoneCol = businessColumns.find(c => 
                c.label.toLowerCase().includes("mobile") || 
                c.label.toLowerCase().includes("contact") ||
                c.label.toLowerCase().includes("phone")
              );
              if (phoneCol && !newData[phoneCol.key]) {
                newData[phoneCol.key] = phone;
              }
              return newData;
            });
          }
        } else {
          // Team Member
          setMasterFormData(prev => ({
            ...prev,
            name: prev.name || name,
            contact: prev.contact || phone
          }));
        }

        setNotification({
          message: `✅ Picked: ${name}`,
          type: "success"
        });
      }
    } catch (err: any) {
      console.error("Contact picker error:", err);
      if (err.name !== "AbortError") {
        setNotification({
          message: "❌ Failed to access contacts.",
          type: "error"
        });
      }
    }
  };
  const handleForceAppUpdate = async () => {
    try {
      setNotification({
        message: "🔄 Forcing application update and clearing cache...",
        type: "info",
      });

      // Clear Service Worker Caches
      if ("caches" in window) {
        const cacheNames = await caches.keys();
        await Promise.all(
          cacheNames.map((name) => caches.delete(name)),
        );
      }

      // Unregister Service Workers
      if ("serviceWorker" in navigator) {
        const registrations = await navigator.serviceWorker.getRegistrations();
        for (const registration of registrations) {
          await registration.unregister();
        }
      }

      // Clear specific local storage items that might be stale
      // Force clearing master tasks to ensure they are re-downloaded from Cloud
      const keysToClear = [
        "arya_weekly_tasks",
        "arya_monthly_tasks",
        "arya_yearly_tasks",
        "arya_quarterly_tasks",
        "arya_app_version",
        "arya_admin_action_items",
        "arya_business_master",
        "arya_team_master",
        "arya_task_reminders",
        "arya_dashboard_data",
        "arya_dashboard_logs"
      ];
      keysToClear.forEach(key => localStorage.removeItem(key));

      setNotification({
        message: "✅ Cache & Local Storage cleared. Reloading...",
        type: "success",
      });

      // Force reload from server with strict cache-busting timestamp
      setTimeout(() => {
        const cleanUrl = window.location.origin + window.location.pathname;
        window.location.replace(cleanUrl + "?v=" + APP_VERSION + "&cb=" + Date.now());
      }, 1500);
    } catch (err) {
      console.error("Force update failed:", err);
      setNotification({
        message: "❌ Update failed. Please try manual refresh.",
        type: "error",
      });
    }
  };

  const handleGuestLogin = async () => {
    if (!guestName || !guestEmail) {
      setGuestLoginError("Please enter both name and email.");
      return;
    }
    if (!guestEmail.includes("@")) {
      setGuestLoginError("Please enter a valid email.");
      return;
    }
    if (!isGuestTermsAccepted) {
      setGuestLoginError("You must accept the terms and conditions.");
      return;
    }

    try {
      setGuestLoginError("");
      setCloudStatus("SYNCING");
      const token =
        Math.random().toString(36).substring(2, 15) +
        Math.random().toString(36).substring(2, 15);
      
      setGuestSentToken(token);

      const response = await fetch("/api/send-guest-link", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        credentials: "include",
        body: JSON.stringify({ email: guestEmail, name: guestName, token }),
      });

      const result = await response.json();
      if (result.success) {
        setIsGuestLinkSent(true);
        setNotification({
          message: "Verification link & code sent! Check your email.",
          type: "success",
        });
      } else {
        setGuestLoginError(
          result.error || "Failed to send verification email.",
        );
        if (result.debugLink) {
          setGuestDebugLink(result.debugLink);
        }
      }
    } catch (err: any) {
      setGuestLoginError("Network error. Please try again.");
    } finally {
      setCloudStatus("IDLE");
    }
  };

