  const isTaskScheduledForDate = (task: TaskRow, date: Date) => {
    const dayName = date
      .toLocaleDateString("en-US", { weekday: "long" })
      .toUpperCase();
    const dateNum = date.getDate();
    const monthName = date
      .toLocaleDateString("en-US", { month: "long" })
      .toUpperCase();

    if (task.type === "WEEKLY") {
      return task.dayOrDate.toUpperCase() === dayName;
    }

    if (task.type === "MONTHLY") {
      const parts = task.dayOrDate.split("-");
      if (parts.length === 1) {
        return parseInt(parts[0]) === dateNum;
      } else {
        const start = parseInt(parts[0]);
        const end = parseInt(parts[1]);
        return dateNum >= start && dateNum <= end;
      }
    }

    if (task.type === "QUARTERLY") {
      const currentMonthIndex = date.getMonth();
      const monthShorts = [
        "JAN",
        "FEB",
        "MAR",
        "APR",
        "MAY",
        "JUN",
        "JUL",
        "AUG",
        "SEP",
        "OCT",
        "NOV",
        "DEC",
      ];
      const monthLongs = [
        "JANUARY",
        "FEBRUARY",
        "MARCH",
        "APRIL",
        "MAY",
        "JUNE",
        "JULY",
        "AUGUST",
        "SEPTEMBER",
        "OCTOBER",
        "NOVEMBER",
        "DECEMBER",
      ];

      const qRange = task.dayOrDate.toUpperCase();
      const parts = qRange.split("-");

      if (parts.length === 2) {
        const getIdx = (m: string) => {
          const s = m.trim().substring(0, 3);
          const i = monthShorts.indexOf(s);
          if (i !== -1) return i;
          return monthLongs.indexOf(m.trim());
        };
        const startIdx = getIdx(parts[0]);
        const endIdx = getIdx(parts[1]);

        if (startIdx !== -1 && endIdx !== -1) {
          if (startIdx <= endIdx)
            return currentMonthIndex >= startIdx && currentMonthIndex <= endIdx;
          return currentMonthIndex >= startIdx || currentMonthIndex <= endIdx;
        }
      }
      return qRange.includes(monthName);
    }

    return false;
  };

