  const sendEmailReport = async () => {
    setIsSendingEmail(true);
    try {
      // Generate Excel for attachment
      const sevenDaysAgo = Date.now() - 7 * 24 * 60 * 60 * 1000;
      const recentLogs = logs.filter((log) => {
        if (!log.timestamp || !log.timestamp.includes("-")) return false;
        try {
          const [d, m, y] = log.timestamp.split("-");
          const months = [
            "Jan",
            "Feb",
            "Mar",
            "Apr",
            "May",
            "Jun",
            "Jul",
            "Aug",
            "Sep",
            "Oct",
            "Nov",
            "Dec",
          ];
          const monthIndex = months.indexOf(m);
          if (monthIndex === -1) return false;
          const logDate = new Date(parseInt(y), monthIndex, parseInt(d));
          return logDate.getTime() >= sevenDaysAgo;
        } catch (e) {
          return false;
        }
      });

      const worksheet = XLSX.utils.json_to_sheet(
        recentLogs.map((log) => ({
          Timestamp: log.timestamp,
          Business: log.business,
          Task: log.task,
          "Completed By": log.completedBy,
          "Start Time": log.startTime,
          "End Time": log.endTime,
          Status: log.status,
        })),
      );
      const workbook = XLSX.utils.book_new();
      XLSX.utils.book_append_sheet(workbook, worksheet, "Weekly Report");
      const excelBase64 = XLSX.write(workbook, {
        bookType: "xlsx",
        type: "base64",
      });

      const response = await fetch("/api/send-report", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        credentials: "include",
        body: JSON.stringify({
          to: reportEmail,
          subject: `Weekly Performance Report - ARYAASSOCIATES - ${formatDate(new Date())}`,
          body:
            weeklyReportContent ||
            "Please find the attached weekly performance report.",
          attachments: [
            {
              filename: `Weekly_Performance_Report_${formatDate(new Date())}.xlsx`,
              content: excelBase64,
            },
          ],
        }),
      });

      if (!response.ok) {
        let errorText = "Unknown error";
        try {
          const errorData = await response.json();
          errorText =
            errorData.error || errorData.message || JSON.stringify(errorData);
        } catch (e) {
          errorText = await response.text();
        }
        throw new Error(
          `Server returned ${response.status}: ${errorText.substring(0, 150)}`,
        );
      }

      const contentType = response.headers.get("content-type");
      let result: any;
      if (contentType && contentType.includes("application/json")) {
        result = await response.json();
      } else {
        const text = await response.text();
        try {
          result = JSON.parse(text);
        } catch (e) {
          result = { success: response.ok, message: text };
        }
      }

      if (result.success) {
        setNotification({
          message: "✅ Report sent to your email successfully!",
          type: "success",
        });
      } else {
        throw new Error(
          result.error || result.message || "Failed to send email",
        );
      }
    } catch (error: any) {
      console.error("Email Error:", error);
      const errorMsg = error.message;
      if (
        errorMsg.includes("testing mode") ||
        errorMsg.includes("authorized recipient")
      ) {
        setNotification({
          message: `📧 Email Failed: Resend is in testing mode. Domain verification required at resend.com to send to ${reportEmail || "this address"}.`,
          type: "error",
        });
      } else {
        setNotification({
          message: `❌ Email failed: ${errorMsg}. Ensure RESEND_API_KEY is configured in Settings.`,
          type: "error",
        });
      }
    } finally {
      setIsSendingEmail(false);
    }
  };

