  const [businessColumns, setBusinessColumns] = useState<BusinessColumn[]>(
    () => {
      const saved = localStorage.getItem("arya_business_columns");
      let cols = safeJSONParse(saved, INITIAL_BUSINESS_COLUMNS);

      // Migration: ensure contactPerson exists and is next to name
      if (!cols.some((c: any) => c.key === "contactPerson")) {
        const nameIdx = cols.findIndex((c: any) => c.key === "name");
        if (nameIdx !== -1) {
          cols.splice(nameIdx + 1, 0, {
            key: "contactPerson",
            label: "Contact Person",
            visible: true,
            type: "text",
          });
        } else {
          cols.unshift({
            key: "contactPerson",
            label: "Contact Person",
            visible: true,
            type: "text",
          });
        }
      }
      // Migration: ensure whatsappGroup exists
      if (!cols.some((c: any) => c.key === "whatsappGroup")) {
        const contactIdx = cols.findIndex((c: any) => c.key === "contact");
        if (contactIdx !== -1) {
          cols.splice(contactIdx + 1, 0, {
            key: "whatsappGroup",
            label: "Group Icon",
            visible: true,
            type: "text",
          });
        } else {
          cols.push({
            key: "whatsappGroup",
            label: "Group Icon",
            visible: true,
            type: "text",
          });
        }
      }

      // Migration: ensure contactPersonDOB exists
      if (!cols.some((c: any) => c.key === "contactPersonDOB")) {
        const cpIdx = cols.findIndex((c: any) => c.key === "contactPerson");
        if (cpIdx !== -1) {
          cols.splice(cpIdx + 1, 0, {
            key: "contactPersonDOB",
            label: "Contact Person DOB",
            visible: false,
            type: "date",
          });
        } else {
          cols.push({
            key: "contactPersonDOB",
            label: "Contact Person DOB",
            visible: false,
            type: "date",
          });
        }
      }

      // Migration: ensure gst_pan_tan_vat exists
      if (!cols.some((c: any) => c.key === "gst_pan_tan_vat")) {
        const dobIdx = cols.findIndex((c: any) => c.key === "contactPersonDOB");
        if (dobIdx !== -1) {
          cols.splice(dobIdx + 1, 0, {
            key: "gst_pan_tan_vat",
            label: "GST/PAN/TAN/VAT",
            visible: true,
            type: "text",
          });
        } else {
          cols.push({
            key: "gst_pan_tan_vat",
            label: "GST/PAN/TAN/VAT",
            visible: true,
            type: "text",
          });
        }
      }

      // Migration: ensure vat exists
      if (!cols.some((c: any) => c.key === "vat")) {
        cols.push({
          key: "vat",
          label: "VAT Number",
          visible: false,
          type: "text",
        });
      }

      // Migration: hide individual GST, PAN, TAN columns
      cols = cols.map((c: any) => {
        if (["gst", "pan", "tan", "vat"].includes(c.key)) {
          return { ...c, visible: false };
        }
        return c;
      });

      // Migration: update whatsappGroup label if old
      cols = cols.map((c: any) => {
        if (c.key === "whatsappGroup" && c.label === "WhatsApp Group Link") {
          return { ...c, label: "Group Icon" };
        }
        return c;
      });

      // Migration: hide contact and employeeContact columns as they are now merged
      cols = cols.map((c: any) => {
        if (c.key === "contact" || c.key === "employeeContact") {
          return { ...c, visible: false };
        }
        return c;
      });

      // Migration: ensure contact and employeeContact are visible
      if (cols.some((c: any) => c.key === "contact" && !c.visible)) {
        cols = cols.map((c: any) =>
          c.key === "contact" ? { ...c, visible: true } : c,
        );
      }
      if (cols.some((c: any) => c.key === "employeeContact" && !c.visible)) {
        cols = cols.map((c: any) =>
          c.key === "employeeContact" ? { ...c, visible: true } : c,
        );
      }

      // Migration: ensure businessCode exists
      if (!cols.some((c: any) => c.key === "businessCode")) {
        cols.unshift({
          key: "businessCode",
          label: "Business Code",
          visible: true,
          type: "text",
        });
      }

      return cols;
    },
  );

