  // Consolidate global error handling
  useEffect(() => {
    const handleError = (event: ErrorEvent) => {
      console.error("Global Error Details:", {
        message: event.message,
        filename: event.filename,
        lineno: event.lineno,
        colno: event.colno,
        error: event.error,
      });
      const errorMsg =
        event.error?.message ||
        event.message ||
        "Illegal constructor or Unknown Error";
      setNotification({
        message: `❌ System Error: ${errorMsg}`,
        type: "error",
      });
    };

    const handleRejection = (event: PromiseRejectionEvent) => {
      event.preventDefault();
      const reason = event.reason;
      console.error("Unhandled Rejection Details:", {
        reason,
        message: reason?.message,
        stack: reason?.stack,
        type: typeof reason,
      });

      let message = "An unexpected background task failed.";

      if (reason) {
        if (typeof reason === "string") {
          message = reason;
        } else if (reason instanceof Error) {
          message = reason.message;
        } else if (typeof reason === "object") {
          try {
            message = reason.message || reason.error || JSON.stringify(reason);
          } catch (e) {
            message = "A complex error occurred in a background process.";
          }
        }
      }

      // Filter out benign, harmless platform warnings, IndexedDB locks, or Firestore SDK assertion errors
      const lowerMessage = message.toLowerCase();
      if (
        lowerMessage.includes("pending promise was never set") ||
        lowerMessage.includes("internal assertion failed") ||
        lowerMessage.includes("indexeddb") ||
        lowerMessage.includes("quota")
      ) {
        console.warn("Ignored benign background task rejection:", message);
        return;
      }

      setNotification({
        message: `⚠️ Background Task Error: ${message.length > 100 ? message.substring(0, 100) + "..." : message}`,
        type: "error",
      });
    };

    window.addEventListener("error", handleError);
    window.addEventListener("unhandledrejection", handleRejection);

    return () => {
      window.removeEventListener("error", handleError);
      window.removeEventListener("unhandledrejection", handleRejection);
    };
  }, []);

  // Load large data from IndexedDB (with localStorage migration)
  useEffect(() => {
    const checkNewDay = async () => {
      try {
        const todayStr = new Date().toISOString().split("T")[0];
        const lastReset = localStorage.getItem("arya_last_reset_date");

        if (lastReset && lastReset !== todayStr) {
          console.log(
            "New day detected (" +
              todayStr +
              "). Clearing sessions and local tasks.",
          );

          // Clear Day-specific local data
          await set("arya_dashboard_work_sessions", {});
          localStorage.removeItem("arya_task_start_times");
          localStorage.setItem("arya_last_reset_date", todayStr);

          setWorkSessions({});
          setTaskStartTimes({});
          setData({}); // Clear local task status data

          // Also purge Cloud Sessions and Task Data on new day
          if (auth.currentUser) {
            const collectionsToClear = ["workSessions", "taskData"];
            for (const coll of collectionsToClear) {
              const q = query(collection(db, coll));
              const s = await getDocs(q);
              let batch = writeBatch(db);
              let c = 0;
              for (const d of s.docs) {
                batch.delete(d.ref);
                c++;
                if (c >= 450) {
                  await batch.commit();
                  batch = writeBatch(db);
                  c = 0;
                }
              }
              if (c > 0) await batch.commit();
            }
            console.log("Cloud sessions/tasks cleared for the new day.");
          }
        } else if (!lastReset) {
          localStorage.setItem("arya_last_reset_date", todayStr);
        }
      } catch (e) {
        console.warn("New Day reset failed:", e);
      }
    };

    const loadLargeData = async () => {
      try {
        // 1. Initial New Day Check
        await checkNewDay();

        // 2. Handle businessFiles
        const savedFiles = await get("arya_business_files");
        if (savedFiles) {
          setBusinessFiles(savedFiles);
        } else {
          // Migration from localStorage
          const localFiles = localStorage.getItem("arya_business_files");
          if (localFiles) {
            const parsed = safeJSONParse(localFiles, {});
            setBusinessFiles(parsed);
            await set("arya_business_files", parsed);
            localStorage.removeItem("arya_business_files");
            console.log("Migrated businessFiles to IndexedDB");
          }
        }

        // 2. Handle workSessions
        const savedSessions = await get("arya_dashboard_work_sessions");
        if (savedSessions) {
          setWorkSessions(savedSessions);
        } else {
          // Migration from localStorage
          const localSessions = localStorage.getItem(
            "arya_dashboard_work_sessions",
          );
          if (localSessions) {
            const parsed = safeJSONParse(localSessions, {});
            setWorkSessions(parsed);
            await set("arya_dashboard_work_sessions", parsed);
            localStorage.removeItem("arya_dashboard_work_sessions");
            console.log("Migrated workSessions to IndexedDB");
          }
        }

        // 3. Handle customTaskDescriptions
        const savedCustomTasks = await get("arya_custom_task_descriptions");
        if (savedCustomTasks) {
          setCustomTaskDescriptions(savedCustomTasks);
        } else {
          const localCustomTasks = localStorage.getItem(
            "arya_custom_task_descriptions",
          );
          if (localCustomTasks) {
            const parsed = safeJSONParse(localCustomTasks, {});
            setCustomTaskDescriptions(parsed);
            await set("arya_custom_task_descriptions", parsed);
          }
        }
      } catch (err) {
        console.error("Error loading data from IndexedDB:", err);
        throw err; // Rethrow to let the caller's .catch handle notification
      }
    };
    loadLargeData().catch((err) => {
      console.error("Critical: loadLargeData failed:", err);
      setNotification({
        message: "❌ Failed to load application data. Please refresh.",
        type: "error",
      });
    });

    // Watcher for new day (checks every 5 minutes if app is left open)
    const interval = setInterval(checkNewDay, 300000);
    return () => clearInterval(interval);
  }, [auth.currentUser]);

