  // Persist App Settings and Sync to Cloud
  useEffect(() => {
    // Local persistence
    if (whatsappNumber) safeLocalStorageSetItem("arya_whatsapp_number", whatsappNumber);
    if (lastSyncSpreadsheetId) safeLocalStorageSetItem("lastSyncSpreadsheetId", lastSyncSpreadsheetId);
    if (businessSheetId) safeLocalStorageSetItem("arya_business_sheet_id", businessSheetId);
    if (businessSheetRange) safeLocalStorageSetItem("arya_business_sheet_range", businessSheetRange);

    // Also save to cloud for synchronization across devices
    // CRITICAL: Only sync if we have values to avoid wiping out cloud data with empty local state
    // AND wait until initial cloud load is finished to avoid overwriting cloud with stale local data
    if (currentUser && userRole === "ADMIN" && appSettingsSyncLoaded.current && !isUpdatingConfigFromCloud.current) {
      if (!whatsappNumber && !lastSyncSpreadsheetId && !businessSheetId && !reportEmail && !defaultEmail) return;

      const timeoutId = setTimeout(async () => {
        try {
          const updateData: any = {};
          if (whatsappNumber) updateData.whatsappNumber = whatsappNumber;
          if (lastSyncSpreadsheetId) updateData.lastSyncSpreadsheetId = lastSyncSpreadsheetId;
          if (businessSheetId) updateData.businessSheetId = businessSheetId;
          if (businessSheetRange) updateData.businessSheetRange = businessSheetRange;
          if (reportEmail) updateData.reportEmail = reportEmail;
          if (defaultEmail) updateData.defaultEmail = defaultEmail;
          if (reportFrequency) updateData.reportFrequency = reportFrequency;
          if (storedAdminPassword) updateData.adminPassword = storedAdminPassword;
          if (storedTeamPassword) updateData.teamPassword = storedTeamPassword;
          if (lastEmailSentDate) updateData.lastEmailSentDate = lastEmailSentDate;

          if (Object.keys(updateData).length > 0) {
            await setDoc(doc(db, "appConfig", "system"), updateData, { merge: true });
            console.log("App settings synced to cloud (appConfig/system)");
          }
        } catch (e) {
          console.error("Failed to sync app settings to cloud:", e);
        }
      }, 5000); // 5s debounce for settings
      return () => clearTimeout(timeoutId);
    }
    
  }, [whatsappNumber, lastSyncSpreadsheetId, businessSheetId, businessSheetRange, reportEmail, defaultEmail, reportFrequency, storedAdminPassword, storedTeamPassword, currentUser, userRole, lastEmailSentDate]);
  const [isCloudLoadedState, setIsCloudLoadedState] = useState(false);
