  const shareReport = (
    taskType:
      | "PENDING"
      | "DONE"
      | "ALL"
      | "EXTRA_WORK"
      | "TOMORROW"
      | "ADMIN"
      | "BUSINESS_MASTER"
      | "TODAY"
      | "ADMIN_TASKS",
    format: "EXCEL" | "PDF",
  ) => {
    try {
      let dataToExport: any[] = [];
      let filename = `Report_${taskType}_${formatDate(new Date())}`;

      if (taskType === "EXTRA_WORK") {
        dataToExport = extraWorks.map((w) => ({
          Date: formatDate(new Date(w.date)),
          Business: w.businessName,
          Work: w.description,
          Charges: w.charges,
          Received: w.receivedAmount || 0,
          Status: w.status,
        }));
      } else if (taskType === "BUSINESS_MASTER") {
        dataToExport = businessMaster.map((b) => {
          const row: any = {};
          businessColumns
            .filter((c) => c.visible)
            .forEach((c) => {
              row[c.label] = b[c.key] || "";
            });
          return row;
        });
      } else if (taskType === "TOMORROW") {
        const tomorrowDate = new Date();
        tomorrowDate.setDate(tomorrowDate.getDate() + 1);
        businesses.forEach((b) => {
          const tTasks = allTasks.filter((t) =>
            isTaskScheduledForDate(t, tomorrowDate),
          );
          tTasks.forEach((t) => {
            dataToExport.push({
              Business: b.name,
              Task: t.description,
              Type: t.type,
              Assigned: b.teamMember,
              Status: data[t.id]?.[b.id]?.status || "PENDING",
            });
          });
        });
      } else if (taskType === "TODAY") {
        businesses.forEach((b) => {
          const tTasks = allTasks.filter((t) =>
            isTaskScheduledForDate(t, today),
          );
          tTasks.forEach((t) => {
            dataToExport.push({
              Business: b.name,
              Task: t.description,
              Type: t.type,
              Assigned: b.teamMember,
              Status: data[t.id]?.[b.id]?.status || "PENDING",
            });
          });
        });
      } else if (taskType === "ADMIN" || taskType === "ADMIN_TASKS") {
        dataToExport = adminTasks.map((t) => ({
          Task: t.description || t.text || "",
          Due: t.dueDate,
          Assigned: t.assignedBy,
          Status: t.status,
        }));
      } else {
        const activeBusinesses =
          userRole === "BUSINESS"
            ? businesses.filter((b) => b.id === currentBusinessUser)
            : userRole === "TEAM"
              ? businesses.filter(
                  (b) =>
                    b.teamMember?.toLowerCase() ===
                    currentTeamUser?.toLowerCase(),
                )
              : businesses;

        activeBusinesses.forEach((b) => {
          const bTasks = allTasks.filter((t) => {
            const status = data[t.id]?.[b.id]?.status || "PENDING";
            if (taskType === "PENDING")
              return status === "PENDING" || status === "IN PROGRESS";
            if (taskType === "DONE") return status === "DONE";
            return true;
          });
          bTasks.forEach((t) => {
            dataToExport.push({
              Business: b.name,
              Task: t.description,
              Status: data[t.id]?.[b.id]?.status || "PENDING",
            });
          });
        });
      }

      if (dataToExport.length === 0) {
        setNotification({ message: "No data to export", type: "info" });
        return;
      }

      if (format === "EXCEL") {
        const worksheet = XLSX.utils.json_to_sheet(dataToExport);
        const workbook = XLSX.utils.book_new();
        XLSX.utils.book_append_sheet(workbook, worksheet, "Report");
        const excelBuffer = XLSX.write(workbook, { bookType: "xlsx", type: "array" });
        const blob = new Blob([excelBuffer], { type: "application/vnd.openxmlformats-officedocument.spreadsheetml.sheet" });
        
        triggerGlobalShare({
          title: filename.replace(/_/g, " "),
          text: `ARYAASSOCIATES ${taskType.replace(/_/g, " ")} Report (Excel). Please find the file attached.`,
          file: { blob, name: `${filename}.xlsx`, type: blob.type }
        });
      } else {
        let doc: any;
        try {
          doc = new jsPDF();
        } catch (e) {
          console.error("jsPDF constructor failed in shareReport (PDF):", e);
          setNotification({
            message: "❌ PDF Generation failed: Browser restriction.",
            type: "error",
          });
          return;
        }
        doc.setFontSize(18);
        doc.text(filename.replace(/_/g, " "), 20, 20);
        const headers = Object.keys(dataToExport[0] || {});
        const body = dataToExport.map((item) => Object.values(item));
        autoTable(doc, {
          head: [headers],
          body: body,
          startY: 30,
          styles: { fontSize: 8 },
        });
        const pdfBlob = doc.output("blob");
        
        triggerGlobalShare({
          title: filename.replace(/_/g, " "),
          text: `ARYAASSOCIATES ${taskType.replace(/_/g, " ")} Report (PDF). Please find the file attached.`,
          file: { blob: pdfBlob, name: `${filename}.pdf`, type: "application/pdf" }
        });
      }
      setNotification({ message: "✅ Report ready to share!", type: "success" });
    } catch (error) {
      console.error("shareReport failed:", error);
      setNotification({
        message: "⚠️ Report generation failed.",
        type: "error",
      });
    }
  };

