  const importMasterExcel = (e: ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onerror = () => {
      setNotification({
        message: "❌ Error reading Excel file",
        type: "error",
      });
      if (masterImportRef.current) masterImportRef.current.value = "";
    };
    reader.onload = (evt) => {
      try {
        const bstr = evt.target?.result;
        if (!bstr) throw new Error("No data received from file");

        const wb = XLSX.read(bstr, { type: "binary" });
        const wsname = wb.SheetNames[0];
        const ws = wb.Sheets[wsname];
        const data = XLSX.utils.sheet_to_json(ws);

        if (masterType === "BUSINESS") {
          const importedBusinesses: BusinessMaster[] = data.map(
            (row: any, index) => {
              const lastCode =
                businesses.length > 0
                  ? Math.max(
                      ...businesses.map((b) =>
                        parseInt(b.businessCode || "1000"),
                      ),
                    )
                  : 1000;

              const business: any = {
                id: `c${businesses.length + index + 1}`,
                businessCode: (lastCode + index + 1).toString(),
              };
              businessColumns.forEach((col) => {
                if (row[col.label] !== undefined) {
                  business[col.key] = row[col.label];
                }
              });
              return business as BusinessMaster;
            },
          );

          if (importedBusinesses.length > 0) {
            setBusinesses((prev) => [...prev, ...importedBusinesses]);
            setNotification({
              message: `✅ Successfully imported ${importedBusinesses.length} businesses.`,
              type: "success",
            });
          }
        } else {
          const importedTeam: TeamMaster[] = data.map((row: any, index) => ({
            id: `t${teamMaster.length + index + 1}`,
            name: row["Member Name"] || row["Name"] || "",
            contact: row["Contact Number"] || row["Contact"] || "",
            mainRole: "MAIN",
            subRole: "SUB",
          }));

          if (importedTeam.length > 0) {
            setTeamMaster((prev) => [...prev, ...importedTeam]);
            setNotification({
              message: `✅ Successfully imported ${importedTeam.length} team members.`,
              type: "success",
            });
          }
        }
      } catch (error) {
        console.error("Import error:", error);
        setNotification({
          message: "❌ Failed to import Excel file. Please check the format.",
          type: "error",
        });
      }
      if (masterImportRef.current) masterImportRef.current.value = "";
    };
    reader.readAsBinaryString(file);
  };

