  const isHighlighted = (task: any) => {
    if (task.type === "WEEKLY") {
      return task.dayOrDate === currentDayName;
    }
    if (task.type === "MONTHLY") {
      if (task.dayOrDate.includes("-")) {
        const [start, end] = task.dayOrDate.split("-").map(Number);
        return currentDate >= start && currentDate <= end;
      }
      return Number(task.dayOrDate) === currentDate;
    }
    if (task.type === "YEARLY") {
      const currentMonthName = today
        .toLocaleDateString("en-US", { month: "long" })
        .toUpperCase();
      return task.dayOrDate.toUpperCase() === currentMonthName;
    }
    if (task.type === "QUARTERLY") {
      return isTaskScheduledForDate(task, today);
    }
    return false;
  };

