  // Automatic Email for Undownloaded Papers (1 Week)
  useEffect(() => {
    const checkUndownloadedFiles = () => {
      const oneWeekAgo = Date.now() - 7 * 24 * 60 * 60 * 1000;
      let filesToEmail: { businessName: string; fileName: string }[] = [];

      Object.entries(businessFiles).forEach(([businessId, files]) => {
        const business = businesses.find((b) => b.id === businessId);
        if (!business) return;

        (files as any[]).forEach((file) => {
          if (
            !file.downloaded &&
            file.uploadTimestamp < oneWeekAgo &&
            !file.emailed
          ) {
            filesToEmail.push({
              businessName: business.name,
              fileName: file.name,
            });

            // Mark as emailed to prevent duplicate emails in this session
            setBusinessFiles((prev) => ({
              ...prev,
              [businessId]: prev[businessId].map((f) =>
                f.name === file.name ? { ...f, emailed: true } : f,
              ),
            }));
          }
        });
      });

      if (filesToEmail.length > 0) {
        const emailBody = filesToEmail
          .map((f) => `• Client: ${f.businessName} | Document: ${f.fileName}`)
          .join("\n");
        const subject = `Urgent: Undownloaded Working Papers Alert`;
        const fullMessage = `The following documents have not been downloaded by the team/admin for over a week:\n\n${emailBody}\n\nPlease review them immediately.`;

        console.log(`[TRIGGERING EMAIL TO ${defaultEmail}]`, {
          subject,
          message: fullMessage,
        });

        // Trigger real email via API
        fetch("/api/send-report", {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          credentials: "include",
          body: JSON.stringify({
            to: defaultEmail,
            subject: subject,
            body: fullMessage,
          }),
        }).catch((err) => console.error("Auto-Alert Error:", err));

        setNotification({
          message: `📧 Auto-Email sent to ${defaultEmail} for ${filesToEmail.length} pending documents.`,
          type: "success",
        });

        // Log the auto-email
        const newLog: LogEntry = {
          id: Date.now().toString(),
          timestamp: new Date().toLocaleString(),
          date: Date.now(),
          business: "SYSTEM",
          task: `Auto-Email: Undownloaded Papers Alert sent to ${defaultEmail}`,
          status: "DONE",
          completedBy: "SYSTEM",
          startTime: "N/A",
          endTime: new Date().toLocaleTimeString(),
        };
        setLogs((prev) => [newLog, ...prev]);
      }
    };

    // Check every hour (simulated)
    const interval = setInterval(checkUndownloadedFiles, 60 * 60 * 1000);
    // Initial check
    checkUndownloadedFiles();

    return () => clearInterval(interval);
  }, [businessFiles, businesses, defaultEmail]);

