  const handleMasterFreshStart = async () => {
    if (userRole !== "ADMIN") return;

    showConfirm(
      "🚨 FRESH START: ERASE EVERYTHING?",
      "Yeh option Cloud (Online) aur Local (Offline) saara data permanently delete kar dega. Iske baad aapka portal bilkul naya ho jayega. Kya aap sure hain?",
      async () => {
        try {
          setNotification({
            message: "🔄 Initializing Portal Reset...",
            type: "info",
          });

          // 1. Clear Local Storage & IndexedDB
          Object.keys(localStorage).forEach((key) => {
            if (key.startsWith("arya_")) localStorage.removeItem(key);
          });
          const idbToClear = [
            "arya_business_files",
            "arya_dashboard_work_sessions",
            "arya_team_members",
            "arya_custom_task_descriptions",
            "arya_business_columns",
            "arya_business_master",
            "arya_team_master",
          ];
          for (const k of idbToClear) await del(k);

          // 2. Clear Firestore Collections
          const collectionsToPurge = [
            "businesses",
            "teamMembers",
            "taskData",
            "workSessions",
            "internalAdminTasks",
            "businessActionItems",
            "extraWorks",
            "logs",
            "customTaskDescriptions",
            "config",
            "settings",
          ];

          for (const collName of collectionsToPurge) {
            try {
              const q = query(collection(db, collName));
              const snapshot = await getDocs(q);

              if (snapshot.empty) continue;

              // Firestore batches are limited to 500 ops
              let batch = writeBatch(db);
              let count = 0;
              for (const docSnap of snapshot.docs) {
                batch.delete(docSnap.ref);
                count++;
                if (count >= 450) {
                  // Safety margin
                  await batch.commit();
                  batch = writeBatch(db);
                  count = 0;
                }
              }
              if (count > 0) await batch.commit();
              console.log(`Purged collection: ${collName}`);
            } catch (e) {
              console.warn(`Could not purge collection ${collName}:`, e);
            }
          }

          // 3. Reset State
          setLogs([]);
          setBusinessMaster([]);
          setTeamMaster([]);
          setData({});
          setWorkSessions({});
          setBusinessFiles({});
          setTaskStartTimes({});

          setNotification({
            message: "✅ Portal Reset Successful! Restarting...",
            type: "success",
          });
          setTimeout(() => window.location.reload(), 2000);
        } catch (err) {
          console.error("Purge failed:", err);
          setNotification({
            message: "❌ Error during fresh start",
            type: "error",
          });
        }
      },
      "danger",
    );
  };

  const handleMasterReset = async () => {
    // Same robust logic as fresh start but explicitly for total reset
    handleMasterFreshStart();
  };

  const handleClearDailyLogs = async () => {
    showConfirm(
      "Clear Logs?",
      "Are you sure you want to clear all History Logs and Work Sessions? This will keep your Businesses and Team Members intact.",
      async () => {
        try {
          // Clear Local
          setLogs([]);
          setWorkSessions({});
          await del("arya_dashboard_work_sessions");
          localStorage.removeItem("arya_dashboard_logs");
          localStorage.removeItem("arya_dashboard_work_sessions");

          // Clear Firestore
          const collectionsToPurge = ["logs", "workSessions"];
          for (const collName of collectionsToPurge) {
            try {
              const q = query(collection(db, collName));
              const snapshot = await getDocs(q);
              const batch = writeBatch(db);
              snapshot.docs.forEach((docSnap) => batch.delete(docSnap.ref));
              await batch.commit();
            } catch (e) {
              console.warn(`Could not purge collection ${collName}:`, e);
            }
          }

          setNotification({
            message:
              "✅ History logs and sessions cleared from server and local!",
            type: "success",
          });
          calculateStorageUsage();
        } catch (err) {
          console.error("Clear Logs Error:", err);
          setNotification({ message: "❌ Error clearing logs", type: "error" });
        }
      },
    );
  };

  const [editingTaskId, setEditingTaskId] = useState<string | null>(null);
  const [customizingTaskId, setCustomizingTaskId] = useState<string | null>(
    null,
  );
  const [customDescSearch, setCustomDescSearch] = useState("");
  const [newTaskData, setNewTaskData] = useState({
    type: "WEEKLY" as any,
    dayOrDate: "",
    description: "",
    assignedTo: "ALL",
    dueDate: "",
    reminderDays: 2,
  });

  const handleAddTask = () => {
    if (!newTaskData.dayOrDate || !newTaskData.description) return;
    const newTask: TaskRow = {
      id: Date.now().toString(),
      ...newTaskData,
    };
    if (newTaskData.type === "WEEKLY")
      setWeeklyTasks([...weeklyTasks, newTask]);
    else if (newTaskData.type === "MONTHLY")
      setMonthlyTasks([...monthlyTasks, newTask]);
    else if (newTaskData.type === "QUARTERLY")
      setQuarterlyTasks([...quarterlyTasks, newTask]);
    else setYearlyTasks([...yearlyTasks, newTask]);
    setNewTaskData({
      type: "WEEKLY",
      dayOrDate: "",
      description: "",
      assignedTo: "ALL",
      dueDate: "",
      reminderDays: 2,
    });
  };

  const handleDeleteTask = (id: string, type: string) => {
    if (type === "WEEKLY")
      setWeeklyTasks(weeklyTasks.filter((t) => t.id !== id));
    else if (type === "MONTHLY")
      setMonthlyTasks(monthlyTasks.filter((t) => t.id !== id));
    else if (type === "QUARTERLY")
      setQuarterlyTasks(quarterlyTasks.filter((t) => t.id !== id));
    else setYearlyTasks(yearlyTasks.filter((t) => t.id !== id));
  };

  const handleEditTask = (task: TaskRow) => {
    if (task.type === "WEEKLY")
      setWeeklyTasks(weeklyTasks.map((t) => (t.id === task.id ? task : t)));
    else if (task.type === "MONTHLY")
      setMonthlyTasks(monthlyTasks.map((t) => (t.id === task.id ? task : t)));
    else if (task.type === "QUARTERLY")
      setQuarterlyTasks(
        quarterlyTasks.map((t) => (t.id === task.id ? task : t)),
      );
    else setYearlyTasks(yearlyTasks.map((t) => (t.id === task.id ? task : t)));
  };

  const moveTask = (
    id: string,
    type: "WEEKLY" | "MONTHLY" | "QUARTERLY" | "YEARLY",
    direction: "UP" | "DOWN",
  ) => {
    const setter =
      type === "WEEKLY"
        ? setWeeklyTasks
        : type === "MONTHLY"
          ? setMonthlyTasks
          : type === "QUARTERLY"
            ? setQuarterlyTasks
            : setYearlyTasks;
    const tasks =
      type === "WEEKLY"
        ? weeklyTasks
        : type === "MONTHLY"
          ? monthlyTasks
          : type === "QUARTERLY"
            ? quarterlyTasks
            : yearlyTasks;

    const index = tasks.findIndex((t) => t.id === id);
    if (index === -1) return;

    const newTasks = [...tasks];
    if (direction === "UP" && index > 0) {
      [newTasks[index - 1], newTasks[index]] = [
        newTasks[index],
        newTasks[index - 1],
      ];
    } else if (direction === "DOWN" && index < tasks.length - 1) {
      [newTasks[index + 1], newTasks[index]] = [
        newTasks[index],
        newTasks[index + 1],
      ];
    }
    setter(newTasks);
  };

  const handleUpdateCustomDescription = (
    taskId: string,
    businessId: string,
    description: string,
  ) => {
    setCustomTaskDescriptions((prev) => {
      const taskMap = prev[taskId] || {};
      if (!description) {
        const { [businessId]: _, ...rest } = taskMap;
        if (Object.keys(rest).length === 0) {
          const { [taskId]: __, ...otherTasks } = prev;
          return otherTasks;
        }
        return { ...prev, [taskId]: rest };
      }
      return {
        ...prev,
        [taskId]: { ...taskMap, [businessId]: description },
      };
    });
  };

  const getCurrentLocation = (): Promise<{
    lat: number;
    lng: number;
  } | null> => {
    return new Promise((resolve) => {
      if (!navigator.geolocation) {
        console.error("Geolocation is not supported by this browser.");
        resolve(null);
        return;
      }
      navigator.geolocation.getCurrentPosition(
        (position) => {
          resolve({
            lat: position.coords.latitude,
            lng: position.coords.longitude,
          });
        },
        (error) => {
          console.error("Error getting location:", error);
          resolve(null);
        },
        { enableHighAccuracy: true, timeout: 10000, maximumAge: 0 },
      );
    });
  };

  const handleStartWork = async (businessId: string) => {
    const now = new Date().toLocaleTimeString([], {
      hour: "2-digit",
      minute: "2-digit",
    });

    // Get location
    const location = await getCurrentLocation();

    setWorkSessions((prev) => {
      const current = prev[businessId] || {};
      const sessions = current.sessions || [];

      // Add new session
      const newSession = {
        startTime: now,
        endTime: "",
        startLocation: location || undefined,
      };

      return {
        ...prev,
        [businessId]: {
          ...current,
          startTime: current.startTime || now, // Keep first start time for compatibility
          startLocation: current.startLocation || location || undefined,
          sessions: [...sessions, newSession],
        },
      };
    });

    if (!location) {
      setNotification({
        message:
          "⚠️ Could not capture start location. Please ensure GPS is on.",
        type: "warning",
      });
    }
  };

  const handleEndWork = async (businessId: string) => {
    const now = new Date().toLocaleTimeString([], {
      hour: "2-digit",
      minute: "2-digit",
    });

    // Get location
    const location = await getCurrentLocation();

    setWorkSessions((prev) => {
      const current = prev[businessId] || {};
      const sessions = [...(current.sessions || [])];

      if (sessions.length > 0) {
        // Update the last session that doesn't have an end time
        const lastSessionIndex = sessions
          .reverse()
          .findIndex((s) => !s.endTime);
        if (lastSessionIndex !== -1) {
          const actualIndex = sessions.length - 1 - lastSessionIndex;
          sessions.reverse(); // put it back to original order
          sessions[actualIndex] = {
            ...sessions[actualIndex],
            endTime: now,
            endLocation: location || undefined,
          };
        } else {
          sessions.reverse(); // put it back to original order
        }
      }

      return {
        ...prev,
        [businessId]: {
          ...current,
          endTime: now, // Update main end time
          endLocation: location || undefined,
          sessions,
        },
      };
    });

    if (!location) {
      setNotification({
        message: "⚠️ Could not capture end location. Please ensure GPS is on.",
        type: "warning",
      });
    }
  };

  const handleToggleAdminAction = (businessId: string, itemId: string) => {
    setAdminActionItems((prev) => {
      const items = prev[businessId] || [];
      const item = items.find((i) => i.id === itemId);
      if (!item) return prev;

      const newStatus = (item.status === "DONE" ? "PENDING" : "DONE") as "PENDING" | "DONE";
      const updated = {
        ...prev,
        [businessId]: items.map((i) =>
          i.id === itemId
            ? {
                ...i,
                status: newStatus,
                checkedBy:
                  newStatus === "DONE"
                    ? currentUser?.email?.split("@")[0] || "ADMIN"
                    : undefined,
              }
            : i,
        ),
      };
      syncToCloud(`businessActionItems/${businessId}`, {
        tasks: updated[businessId],
      });
      setNotification({
        message:
          newStatus === "DONE"
            ? "Task marked as DONE"
            : "Task marked as PENDING",
        type: "success",
      });
      return updated;
    });
  };

  const handleSelfieUpload = (
    businessId: string,
    e: ChangeEvent<HTMLInputElement>,
  ) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onerror = () => {
        setNotification({
          message: "❌ Error reading selfie file",
          type: "error",
        });
      };
      reader.onloadend = () => {
        try {
          if (!reader.result) throw new Error("Selfie data is empty");
          setWorkSessions((prev) => ({
            ...prev,
            [businessId]: {
              ...prev[businessId],
              selfie: reader.result as string,
            },
          }));
        } catch (err: any) {
          console.error("Selfie Upload Error:", err);
          setNotification({ message: "❌ Error saving selfie", type: "error" });
        }
      };
      reader.readAsDataURL(file);
    }
    // Clear the input
    e.target.value = "";
  };

  const handleLogout = () => {
    setUserRole("GUEST");
    setRememberedRole("NONE");
    safeLocalStorageSetItem("arya_remembered_role", "GUEST");
    setCurrentTeamUser(null);
    setCurrentBusinessUser(null);
    localStorage.removeItem("arya_current_team_user");
    localStorage.removeItem("arya_current_business_user");
    setSelectedTeamMember("ALL");
    setBusinessLoginPan("");
    setView("DASHBOARD");
    setIsGuestVerified(false);
    setIsGuestLinkSent(false);
    setIsGuestTermsAccepted(false);
    setGuestName("");
    setGuestEmail("");
    setNotification({ message: "👋 Logged out successfully", type: "success" });
  };

  const handleToggleMemberRole = (id: string, target: "MAIN" | "SUB") => {
    const member = teamMaster.find((t) => t.id === id);
    if (member) {
      if (target === "MAIN") {
        const newRole = member.mainRole === "SUB" ? "MAIN" : "SUB";
        setTeamMaster((prev) =>
          prev.map((t) => (t.id === id ? { ...t, mainRole: newRole } : t)),
        );
        setNotification({
          message: `${member.name} is now ${newRole} Member`,
          type: "success",
        });
      } else {
        const newRole = member.subRole === "SUB" ? "MAIN" : "SUB";
        setTeamMaster((prev) =>
          prev.map((t) => (t.id === id ? { ...t, subRole: newRole } : t)),
        );
        setNotification({
          message: `Sub-User ${member.subUserName} is now ${newRole} Member`,
          type: "success",
        });
      }
    }
  };

  const handleSwapSubToMain = (id: string) => {
    const member = teamMaster.find((t) => t.id === id);
    if (member && member.subUserName) {
      setTeamMaster((prev) =>
        prev.map((t) =>
          t.id === id
            ? {
                ...t,
                name: t.subUserName!,
                contact: t.subUserContact || t.contact,
                subUserName: t.name,
                subUserContact: t.contact,
                mainRole: t.subRole,
                subRole: t.mainRole,
              }
            : t,
        ),
      );
      setNotification({
        message: "Main and Sub users swapped roles & info!",
        type: "success",
      });
    }
  };

  const handleSaveMaster = () => {
    if (masterType === "BUSINESS") {
      const updatedBusiness = { ...masterFormData };

      // Auto-assign unique business code if missing
      if (!updatedBusiness.businessCode) {
        const existingCodes = businesses
          .map((b) => parseInt(b.businessCode || "0"))
          .filter((c) => !isNaN(c));
        const maxCode =
          existingCodes.length > 0 ? Math.max(...existingCodes) : 1000;
        updatedBusiness.businessCode = (maxCode + 1).toString().slice(0, 8);
      } else {
        updatedBusiness.businessCode = updatedBusiness.businessCode
          .toString()
          .slice(0, 8);
      }

      if (editingMasterId) {
        setBusinesses((prev) =>
          prev.map((c) =>
            c.id === editingMasterId ? { ...c, ...updatedBusiness } : c,
          ),
        );
      } else {
        const newId = `c${businesses.length + 1}`;
        const newBusiness = { ...updatedBusiness, id: newId };
        setBusinesses((prev) => [...prev, newBusiness]);
      }
    } else {
      if (editingMasterId) {
        const oldMember = teamMaster.find((t) => t.id === editingMasterId);
        const newMemberData = { ...masterFormData };
        setTeamMaster((prev) =>
          prev.map((t) =>
            t.id === editingMasterId ? { ...t, ...newMemberData } : t,
          ),
        );

        // CASCADING UPDATE: If name changed, update all associations
        if (
          oldMember &&
          newMemberData.name &&
          oldMember.name.trim().toUpperCase() !==
            newMemberData.name.trim().toUpperCase()
        ) {
          const oldName = oldMember.name.trim().toUpperCase();
          const newName = newMemberData.name.trim().toUpperCase();

          // 1. Update Business Assignments
          setBusinesses((prev) =>
            prev.map((b) =>
              (b.teamMember || "").trim().toUpperCase() === oldName
                ? { ...b, teamMember: newName }
                : b,
            ),
          );

          // 2. Update Weekly Tasks
          setWeeklyTasks((prev) =>
            prev.map((t) =>
              (t.assignedTo || "").trim().toUpperCase() === oldName
                ? { ...t, assignedTo: newName }
                : (t.tempAssignedTo || "").trim().toUpperCase() === oldName
                  ? { ...t, tempAssignedTo: newName }
                  : t,
            ),
          );

          // 3. Update Monthly Tasks
          setMonthlyTasks((prev) =>
            prev.map((t) =>
              (t.assignedTo || "").trim().toUpperCase() === oldName
                ? { ...t, assignedTo: newName }
                : (t.tempAssignedTo || "").trim().toUpperCase() === oldName
                  ? { ...t, tempAssignedTo: newName }
                  : t,
            ),
          );

          // 4. Update Yearly Tasks
          setYearlyTasks((prev) =>
            prev.map((t) =>
              (t.assignedTo || "").trim().toUpperCase() === oldName
                ? { ...t, assignedTo: newName }
                : (t.tempAssignedTo || "").trim().toUpperCase() === oldName
                  ? { ...t, tempAssignedTo: newName }
                  : t,
            ),
          );
        }
      } else {
        const newId = `t${teamMaster.length + 1}`;
        const newMember = { ...masterFormData, id: newId };
        setTeamMaster((prev) => [...prev, newMember]);
      }
    }
    setIsAddMasterModalOpen(false);
    setEditingMasterId(null);
    setMasterFormData({});
  };

  useEffect(() => {
    if (editingMasterId) {
      const data =
        masterType === "BUSINESS"
          ? businessMaster.find((c) => c.id === editingMasterId)
          : teamMaster.find((t) => t.id === editingMasterId);
      if (data) setMasterFormData(data);
    } else {
      if (masterType === "BUSINESS") {
        const initialData: any = { id: "" };
        businessColumns.forEach((col) => {
          initialData[col.key] =
            col.type === "select" ? col.options?.[0] || "" : "";
        });
        setMasterFormData(initialData);
      } else {
        setMasterFormData({ name: "", contact: "" });
      }
    }
  }, [editingMasterId, masterType, businessColumns]);

  const handleDeleteTeamMember = (id: string) => {
    const member = teamMaster.find((t) => t.id === id);
    if (member) {
      showConfirm(
        "Remove Team Member?",
        `Are you sure you want to remove ${member.name}?`,
        () => {
          setTeamMaster((prev) => prev.filter((t) => t.id !== id));
          setNotification({
            message: `✅ Removed ${member.name} from team.`,
            type: "success",
          });
        },
        "danger",
      );
    }
  };

  const moveColumn = (index: number, direction: "up" | "down") => {
    const newColumns = [...businessColumns];
    const targetIndex = direction === "up" ? index - 1 : index + 1;
    if (targetIndex < 0 || targetIndex >= newColumns.length) return;
    [newColumns[index], newColumns[targetIndex]] = [
      newColumns[targetIndex],
      newColumns[index],
    ];
    setBusinessColumns(newColumns);
  };

  const addColumn = (
    label: string,
    type: "text" | "date" | "select",
    options?: string[],
  ) => {
    const key = label.toLowerCase().replace(/\s+/g, "_");
    if (businessColumns.some((c) => c.key === key)) {
      setNotification({ message: "⚠️ Column already exists!", type: "error" });
      return;
    }
    const newCol: BusinessColumn = { key, label, visible: true, type, options };
    setBusinessColumns([...businessColumns, newCol]);

    // Add new field to all existing business records
    setBusinessMaster((prev) => prev.map((c) => ({ ...c, [key]: "" })));
  };

  const removeColumn = (key: string) => {
    if (["name", "teamMember"].includes(key)) {
      setNotification({
        message: "⚠️ Cannot remove mandatory columns!",
        type: "error",
      });
      return;
    }
    showConfirm(
      "Remove Column?",
      "Are you sure? This will remove data from all businesses for this column.",
      () => {
        setBusinessColumns((prev) => prev.filter((c) => c.key !== key));
        setBusinessMaster((prev) => {
          return prev.map((c) => {
            const { [key]: _, ...rest } = c;
            return rest as BusinessMaster;
          });
        });
      },
      "danger",
    );
  };

  // Reset mobile index when pagination or filters change
  useEffect(() => {
    setCurrentMobileBusinessIndex(0);
  }, [paginatedBusinesses.length]);

  const stats = useMemo(() => {
    let done = 0;
    let pending = 0;
    const filteredBusinesses =
      userRole === "BUSINESS"
        ? businesses.filter((b: any) => b.id === currentBusinessUser)
        : userRole === "TEAM" || selectedTeamMember !== "ALL"
          ? businesses.filter(
              (b: any) =>
                b.teamMember ===
                (userRole === "TEAM" ? currentTeamUser : selectedTeamMember),
            )
          : businesses;

    allTasks.forEach((task) => {
      filteredBusinesses.forEach((business: any) => {
        const activeMember =
          userRole === "TEAM"
            ? currentTeamUser
            : selectedTeamMember !== "ALL"
              ? selectedTeamMember
              : null;
        const isTaskAssignedToMember =
          activeMember &&
          (task.assignedTo === activeMember ||
            task.tempAssignedTo === activeMember);
        const isBusinessAssignedToMember =
          activeMember && business.teamMember === activeMember;

        const hasSpecificAssignment =
          (task.assignedTo && task.assignedTo !== "ALL") || task.tempAssignedTo;
        const shouldCount =
          !activeMember ||
          (hasSpecificAssignment
            ? isTaskAssignedToMember
            : isBusinessAssignedToMember);

        if (shouldCount) {
          const status = data[task.id]?.[business.id]?.status || "";
          if (status === "DONE") done++;
          else if (
            status !== "N/A" &&
            (status === "PENDING" || status === "IN PROGRESS" || status === "")
          )
            pending++;
        }
      });
    });
    return { done, pending };
  }, [
    allTasks,
    data,
    userRole,
    currentBusinessUser,
    currentTeamUser,
    businesses,
    businessMaster,
    selectedTeamMember,
  ]);

  const filteredLogs = useMemo(() => {
    const activeMember =
      userRole === "TEAM"
        ? currentTeamUser
        : selectedTeamMember !== "ALL"
          ? selectedTeamMember
          : null;

    let result = logs;

    if (userRole === "BUSINESS" && currentBusinessUser) {
      const businessName = businessMaster.find(
        (b) => b.id === currentBusinessUser,
      )?.name;
      result = result.filter((log) => log.business === businessName);
    } else if (historyClientFilter !== "ALL") {
      result = result.filter((log) => log.business === historyClientFilter);
    }

    if (activeMember) {
      result = result.filter((log) => log.completedBy === activeMember);
    }

    return result;
  }, [
    logs,
    userRole,
    currentBusinessUser,
    currentTeamUser,
    businessMaster,
    selectedTeamMember,
    historyClientFilter,
  ]);

  useEffect(() => {
    if (lastEmailSentDate) {
      localStorage.setItem("arya_last_email_sent_date", lastEmailSentDate);
    }
  }, [lastEmailSentDate]);

  const sendReportViaEmail = async (type: "EXCEL" | "PDF", isAuto = false) => {
    try {
      if (!isAuto) {
        setNotification({
          message: "📧 Preparing report and sending email...",
          type: "info",
        });
      }

      let fileName = "";
      let base64Data = "";
      let contentType = "";

      if (type === "EXCEL") {
        const worksheet = XLSX.utils.json_to_sheet(
          filteredLogs.map((log) => ({
            Timestamp: log.timestamp,
            Business: log.business,
            Task: log.task,
            "Completed By": log.completedBy,
            "Start Time": log.startTime,
            "End Time": log.endTime,
            Status: log.status,
          })),
        );
        const workbook = XLSX.utils.book_new();
        XLSX.utils.book_append_sheet(workbook, worksheet, "History Log");
        const excelBuffer = XLSX.write(workbook, {
          bookType: "xlsx",
          type: "base64",
        });
        fileName = `History_Log_${formatDate(new Date())}.xlsx`;
        base64Data = excelBuffer;
        contentType =
          "application/vnd.openxmlformats-officedocument.spreadsheetml.sheet";
      } else {
        let doc: any;
        try {
          doc = new jsPDF();
        } catch (e) {
          console.error(
            "jsPDF constructor failed in sendReportViaEmail (PDF):",
            e,
          );
          if (!isAuto) {
            setNotification({
              message: "❌ PDF Generation failed: Browser restriction.",
              type: "error",
            });
          }
          return;
        }
        doc.setFontSize(18);
        doc.text("ARYAASSOCIATES - Completion History", 14, 22);
        doc.setFontSize(10);
        doc.setTextColor(100);
        doc.text(`Generated on: ${new Date().toLocaleString()}`, 14, 30);

        autoTable(doc, {
          startY: 35,
          head: [["Date", "Business", "Task", "Member", "Start", "End"]],
          body: filteredLogs.map((log) => [
            log.timestamp,
            log.business,
            log.task,
            log.completedBy,
            log.startTime,
            log.endTime,
          ]),
          theme: "striped",
          headStyles: {
            fillColor: [79, 70, 229],
            textColor: 255,
            fontStyle: "bold",
          },
          styles: { fontSize: 8, cellPadding: 3 },
          columnStyles: {
            0: { cellWidth: 25 },
            1: { cellWidth: 30 },
            2: { cellWidth: "auto" },
            3: { cellWidth: 20 },
            4: { cellWidth: 20 },
            5: { cellWidth: 20 },
          },
        });

        base64Data = doc.output("datauristring").split(",")[1];
        fileName = `History_Log_${formatDate(new Date())}.pdf`;
        contentType = "application/pdf";
      }

      // AI Summary for Email Body
      let emailBody = `WEEKLY PERFORMANCE REPORT - ARYA ASSOCIATES\nGenerated on: ${new Date().toLocaleString()}\n\n`;
      
      if (isAuto) {
        try {
          const sevenDaysAgo = new Date();
          sevenDaysAgo.setDate(sevenDaysAgo.getDate() - 7);
          const logSummary = filteredLogs
            .filter((l) => new Date(l.timestamp) > sevenDaysAgo)
            .map((l) => `- ${l.timestamp}: ${l.business} | ${l.task} | Done by ${l.completedBy}`)
            .join("\n");
          
          if (logSummary) {
            const aiSummary = await aiService.generateWeeklySummary(logSummary);
            emailBody += `--- AI PERFORMANCE INSIGHTS ---\n${aiSummary}\n\n`;
          }
        } catch (e) {
          console.warn("AI Email Summary failed:", e);
          emailBody += "(AI Summary was unavailable for this report)\n\n";
        }
      }

      emailBody += `Please find the attached ${type} report for the History Log.\n\n`;
      
      // Add info about purged documents if auto
      if (isAuto) {
        const fileCount = Object.values(businessFiles).flat().length + inboxFiles.length;
        emailBody += `--- STORAGE MAINTENANCE ---\nTotal files purged to save space: ${fileCount}\n`;
        emailBody += `This includes all files from 'Work Papers' and 'Inbox/Unmatched' folders.\n\n`;
      }
      
      emailBody += `(This is an automated weekly report from Arya Associates App)`;

      const response = await fetch("/api/send-report", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        credentials: "include",
        body: JSON.stringify({
          to: reportEmail || "arya4186@gmail.com",
          subject: `${isAuto ? "AUTO: " : ""}ARYA ASSOCIATES Performance Report - ${formatDate(new Date())}`,
          body: emailBody,
          attachments: [
            {
              filename: fileName,
              content: base64Data,
              encoding: "base64",
              contentType: contentType,
            },
          ],
        }),
      });

      const result = await response.json();
      if (result.success) {
        if (!isAuto) {
          setNotification({
            message: "✅ Email sent successfully with attachment!",
            type: "success",
          });
        }
        const timestampIso = new Date().toISOString();
        setLastEmailSentDate(timestampIso);
        localStorage.setItem("arya_last_email_sent_date", timestampIso);
        try {
          await setDoc(doc(db, "appConfig", "system"), { lastEmailSentDate: timestampIso }, { merge: true });
        } catch (e) {
          console.warn("Could not save lastEmailSentDate to Firestore config:", e);
        }
      } else {
        throw new Error(result.error || "Failed to send email");
      }
    } catch (error: any) {
      console.error("Email Error:", error);
      if (!isAuto) {
        let errorMsg = error.message;
        if (
          errorMsg.includes("testing mode") ||
          errorMsg.includes("authorized recipient")
        ) {
          setNotification({
            message: `📧 Email Failed: Resend is in testing mode. Domain verification required at resend.com to send to ${reportEmail || "this address"}.`,
            type: "error",
          });
        } else {
          setNotification({ message: `❌ Error: ${errorMsg}`, type: "error" });
        }
      }
    }
  };

  // Weekly Automation Check
  useEffect(() => {
    if (userRole === "ADMIN" && reportFrequency === "WEEKLY" && reportEmail) {
      const now = new Date();
      const lastSent = lastEmailSentDate ? new Date(lastEmailSentDate) : null;

      // If never sent or sent more than 7 days ago
      if (
        !lastSent ||
        now.getTime() - lastSent.getTime() > 7 * 24 * 60 * 60 * 1000
      ) {
        // Only trigger on Mondays or if forced by time lapse
        if (now.getDay() === 1 || !lastSent) {
          sendReportViaEmail("EXCEL", true).then(async () => {
            // AUTOMATIC PURGE after successful email (as requested by user)
            setNotification({
              message: "🧹 Auto-maintenance: Weekly report emailed. History logs & files cleared from database.",
              type: "info"
            });
            setBusinessFiles({});
            setInboxFiles([]);
            setLogs([]);

            // Permanently clear cloud logs collection from Firestore to empty history tab
            try {
              const q = query(collection(db, "logs"));
              const s = await getDocs(q);
              let batch = writeBatch(db);
              let cnt = 0;
              for (const d of s.docs) {
                batch.delete(d.ref);
                cnt++;
                if (cnt >= 450) {
                  await batch.commit();
                  batch = writeBatch(db);
                  cnt = 0;
                }
              }
              if (cnt > 0) await batch.commit();
              console.log("Weekly auto-maintenance: Firestore logs successfully purged.");
            } catch (err) {
              console.warn("Could not purge logs from Firestore:", err);
            }
          });
        }
      }
    }
  }, [userRole, reportFrequency, reportEmail, lastEmailSentDate]);

  const filteredBusinessMaster = useMemo(() => {
    let base = businessMaster;
    if (userRole === "TEAM" && currentTeamUser) {
      base = businessMaster.filter(
        (b) => b.teamMember?.toLowerCase() === currentTeamUser.toLowerCase(),
      );
    } else if (userRole === "BUSINESS" && currentBusinessUser) {
      base = businessMaster.filter((b) => b.id === currentBusinessUser);
    }

    if (!masterSearchTerm.trim()) return base;
    const term = masterSearchTerm.toLowerCase();
    return base.filter((b) =>
      Object.values(b).some(
        (val) =>
          val !== null &&
          val !== undefined &&
          String(val).toLowerCase().includes(term),
      ),
    );
  }, [
    businessMaster,
    masterSearchTerm,
    userRole,
    currentTeamUser,
    currentBusinessUser,
  ]);

  const filteredTeamMaster = useMemo(() => {
    if (userRole === "BUSINESS") return [];
    let base = teamMaster;
    if (userRole === "TEAM" && currentTeamUser) {
      base = teamMaster.filter((t) => t.name === currentTeamUser);
    }

    if (!masterSearchTerm.trim()) return base;
    const term = masterSearchTerm.toLowerCase();
    return base.filter(
      (t) =>
        t.name.toLowerCase().includes(term) ||
        (t.contact && t.contact.toLowerCase().includes(term)),
    );
  }, [teamMaster, masterSearchTerm, userRole, currentTeamUser]);

